181	// resolveInstallDirs returns the install root directory and agent/claude skill
182	// directories for either a global or project-local install. For project installs,
183	// ddxroot.Path() handles the in-tree vs convention distinction automatically.
184	func (f *CommandFactory) resolveInstallDirs(global bool) (installRoot, agentSkillsDir, claudeSkillsDir string, err error) {
185		if global {
186			installRoot = ddxroot.GlobalDir()
187			home, herr := os.UserHomeDir()
188			if herr != nil {
189				return "", "", "", fmt.Errorf("getting home dir: %w", herr)
190			}
191			agentSkillsDir = filepath.Join(home, ".agents", "skills")
192			claudeSkillsDir = filepath.Join(home, ".claude", "skills")
193			return
194		}
195		installRoot = ddxroot.Path(context.Background(), f.WorkingDir)
196		agentSkillsDir = filepath.Join(f.WorkingDir, ".agents", "skills")
197		claudeSkillsDir = filepath.Join(f.WorkingDir, ".claude", "skills")
198		return
199	}
