343	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
344		if len(oldFiles) == 0 {
345			return 0
346		}
347	
348		newSet := make(map[string]bool, len(newFiles))
349		for _, f := range newFiles {
350			newSet[f] = true
351		}
352	
353		removed := 0
354		for _, f := range oldFiles {
355			if newSet[f] {
356				continue
357			}
358			if installPathContainsAny(f, newFiles) {
359				continue
360			}
361			expanded := registry.ExpandHome(f)
362			if err := os.RemoveAll(expanded); err == nil {
363				removed++
364			}
365		}
366		return removed
367	}
368	
369	func installPathContainsAny(parent string, files []string) bool {
370		parent = filepath.ToSlash(strings.TrimSuffix(parent, string(filepath.Separator)))
371		parent = strings.TrimSuffix(parent, "/")
372		if parent == "" {
373			return false
374		}
375		prefix := parent + "/"
376		for _, f := range files {
377			f = filepath.ToSlash(f)
378			if strings.HasPrefix(f, prefix) {
379				return true
380			}
381		}
382		return false
383	}
