854	func pluginManifestSkillSources(raw any) ([]string, error) {
855		switch v := raw.(type) {
856		case nil:
857			return nil, nil
858		case string:
859			source := cleanPluginManifestPath(v)
860			if source == "" {
861				return nil, nil
862			}
863			return []string{source}, nil
864		case []any:
865			var sources []string
866			for _, item := range v {
867				text, ok := item.(string)
868				if !ok {
869					return nil, fmt.Errorf("skills entries must be strings")
870				}
871				source := cleanPluginManifestPath(text)
872				if source != "" {
873					sources = append(sources, source)
874				}
875			}
876			return sources, nil
877		default:
878			return nil, fmt.Errorf("skills must be a string or array of strings")
879		}
880	}
