898	func addLocalOverlayIgnores(repoRoot string, paths []string) error {
899		excludePath := filepath.Join(repoRoot, ".git", "info", "exclude")
900		if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
901			return err
902		}
903		existing, _ := os.ReadFile(excludePath)
904		text := string(existing)
905	
906		var additions []string
907		for _, p := range paths {
908			pattern := filepath.ToSlash(p)
909			candidates := []string{pattern}
910			if !strings.HasSuffix(pattern, "/") {
911				candidates = append(candidates, pattern+"/")
912			}
913			for _, candidate := range candidates {
914				if !strings.Contains(text, "\n"+candidate+"\n") && !strings.HasPrefix(text, candidate+"\n") {
915					additions = append(additions, candidate)
916				}
917			}
918		}
919		if len(additions) == 0 {
920			return nil
921		}
922	
923		var sb strings.Builder
924		if len(existing) > 0 && !strings.HasSuffix(text, "\n") {
925			sb.WriteString("\n")
926		}
927		if !strings.Contains(text, "# DDx local plugin overlays") {
928			sb.WriteString("\n# DDx local plugin overlays\n")
929		}
930		for _, pattern := range additions {
931			sb.WriteString(pattern)
932			sb.WriteString("\n")
933		}
934		return os.WriteFile(excludePath, append(existing, []byte(sb.String())...), 0o644)
935	}
