951	// localInstallPathIsGitIgnored reports whether rel (a slash path relative to
952	// the local install source root) is gitignored in the source repository.
953	// ddx install --local must not fail validation on broken symlinks that live
954	// under gitignored scratch/tmp paths (e.g. doctor/home/.codex/tmp/...) the
955	// operator never intended to ship. Returns false when the source is not a git
956	// repo or git is unavailable, leaving the well-known-prefix skip list as the
957	// fallback.
958	func localInstallPathIsGitIgnored(root, rel string, cache map[string]bool) bool {
959		rel = strings.TrimSpace(rel)
960		if rel == "" {
961			return false
962		}
963		if cached, ok := cache[rel]; ok {
964			return cached
965		}
966		// git check-ignore exits 0 when the path is ignored, 1 when it is not, and
967		// 128 when the source is not a git repository — treat anything but 0 as
968		// "not ignored" so non-git sources fall through to the prefix skip list.
969		cmd := internalgit.Command(context.Background(), root, "check-ignore", "-q", "--", filepath.FromSlash(rel))
970		ignored := cmd.Run() == nil
971		cache[rel] = ignored
972		return ignored
973	}
