1012	func localInstallPathAliases(path string) []string {
1013		seen := map[string]bool{}
1014		var aliases []string
1015		add := func(candidate string) {
1016			if strings.TrimSpace(candidate) == "" {
1017				return
1018			}
1019			abs, err := filepath.Abs(candidate)
1020			if err != nil {
1021				abs = candidate
1022			}
1023			if !seen[abs] {
1024				seen[abs] = true
1025				aliases = append(aliases, abs)
1026			}
1027		}
1028		add(path)
1029		if resolved, err := filepath.EvalSymlinks(path); err == nil && resolved != "" {
1030			add(resolved)
1031		}
1032		dir := filepath.Dir(path)
1033		base := filepath.Base(path)
1034		if resolvedDir, err := filepath.EvalSymlinks(dir); err == nil && resolvedDir != "" {
1035			add(filepath.Join(resolvedDir, base))
1036		}
1037		return aliases
1038	}
