472	func handleConflictOutput(out interface{}, conflicts []ConflictInfo, opts *UpdateOptions) error {
473		writer := out.(io.Writer)
474		red := color.New(color.FgRed)
475		cyan := color.New(color.FgCyan)
476		green := color.New(color.FgGreen)
477	
478		_, _ = red.Fprintln(writer, "⚠️  MERGE CONFLICTS DETECTED")
479		_, _ = fmt.Fprintln(writer, "")
480	
481		_, _ = fmt.Fprintf(writer, "Found %d conflict(s) that require resolution:\n", len(conflicts))
482		_, _ = fmt.Fprintln(writer, "")
483	
484		// Display detailed conflict information
485		for i, conflict := range conflicts {
486			_, _ = red.Fprintf(writer, "❌ Conflict %d: %s (line %d)\n", i+1, conflict.FilePath, conflict.LineNumber)
487			_, _ = fmt.Fprintln(writer, "")
488		}
489	
490		// Provide resolution guidance
491		_, _ = fmt.Fprintln(writer, "")
492		_, _ = cyan.Fprintln(writer, "🔧 RESOLUTION OPTIONS")
493		_, _ = fmt.Fprintln(writer, "")
494		_, _ = fmt.Fprintln(writer, "Choose one of the following resolution strategies:")
495		_, _ = fmt.Fprintln(writer, "")
496		_, _ = fmt.Fprintln(writer, "  📋 Automatic Resolution:")
497		_, _ = fmt.Fprintln(writer, "    --strategy=ours    Keep your local changes")
498		_, _ = fmt.Fprintln(writer, "    --strategy=theirs  Accept upstream changes")
499		_, _ = fmt.Fprintln(writer, "    --mine             Same as --strategy=ours")
500		_, _ = fmt.Fprintln(writer, "    --theirs           Same as --strategy=theirs")
501		_, _ = fmt.Fprintln(writer, "")
502		_, _ = fmt.Fprintln(writer, "  🔄 Interactive Resolution:")
503		_, _ = fmt.Fprintln(writer, "    --interactive      Resolve conflicts one by one")
504		_, _ = fmt.Fprintln(writer, "")
505		_, _ = fmt.Fprintln(writer, "  ⚡ Force Resolution:")
506		_, _ = fmt.Fprintln(writer, "    --force            Override all conflicts with upstream")
507		_, _ = fmt.Fprintln(writer, "")
508		_, _ = fmt.Fprintln(writer, "  🔙 Abort Update:")
509		_, _ = fmt.Fprintln(writer, "    --abort            Cancel update and restore previous state")
510	
511		_, _ = green.Fprintln(writer, "💡 Examples:")
